import React from 'react';
import { useFormik } from 'formik';
import './App.css'; 
import Main from './main';
import { BrowserRouter, Route, Routes, useNavigate } from 'react-router-dom';
import { Formik, Form, Field } from 'formik';
import * as Yup from 'yup';

const fields = ['Name', 'Address', 'mobile', 'city', 'district', 'census', 'feeder', 'subdivision', 'routecode', 'billmonth', 'billdate', 'duedate', 'fromdate', 'todate', 'consumerno', 'meterno', 'maxdemand', 'feedercode', 'meterrentcode', 'unitcr', 'unitpr', 'unitc', 'reactiveunitcr', 'reactiveunitpr', 'reactiveunitc', 'importcr', 'importpr', 'importc', 'exportcr', 'exportpr', 'exportc', 'security', 'hpkw', 'fixedcharge', 'energycharge', 'mincharge', 'reactivecharge', 'toucharge', 'fuelcharge', 'eleduty', 'meterrent', 'fmc', 'dpc', 'tamt', 'pbill', 'discreb', 'totalamt1', 'arrears', 'solarpr', 'solarbc', 'totalamt2', 'govtrelief', 'totalamt3', 'totalpayment', 'adjustment', 'fpppa', 'totalamt4', 'theft', 'litigation', 'month1', 'month2', 'month3', 'unitmonth1', 'unitmonth2', 'unitmonth3', 'amountmonth1', 'amountmonth2', 'amountmonth3'];

const validationSchema = Yup.object().shape(
  fields.reduce((acc, field) => {
    acc[field] = Yup.string().required('This field is required');
    return acc;
  }, {})
);

const SignupForm = () => {
  const navigate = useNavigate();

  const formik = useFormik({
    initialValues: {
      Name: '',
      Address: '',
      mobile: '',
      city: '',
      district: '',
      census: '',
      feeder:  '',
      subdivision:  '',
      routecode:  '',
      billmonth:  '',
      billdate:  '',
      duedate:  '',
      fromdate:  '',
      todate:  '',
      consumerno:  '',
      meterno:  '',
      maxdemand:  '',
      feedercode:  '',
      meterrentcode:  '',
      unitcr:  '',
      unitpr:  '',
      unitc:  '',
      reactiveunitcr:  '',
      reactiveunitpr:  '',
      reactiveunitc:  '',
      importcr:  '',
      importpr:  '',
      importc:  '',
      exportcr:  '',
      exportpr:  '',
      exportc:  '',
      security:  '',
      hpkw:  '',
      fixedcharge:  '',
      energycharge:  '',
      mincharge:  '',
      reactivecharge:  '',
      toucharge:  '',
      fuelcharge:  '',
      eleduty:  '',
      meterrent:  '',
      fmc:  '',
      dpc:  '',
      tamt:  '',
      pbill:  '',
      discreb:  '',
      totalamt1:  '',
      arrears:  '',
      solarpr:  '',
      solarbc:  '',
      totalamt2:  '',
      govtrelief:  '',
      totalamt3:  '',
      totalpayment:  '',
      adjustment:  '',
      fpppa:  '',
      totalamt4:  '',
      theft:  '',
      litigation:  '',
      month1:  '',
      month2:  '',
      month3:  '',
      unitmonth1:  '',
      unitmonth2:  '',
      unitmonth3:  '',
      amountmonth1:  '',
      amountmonth2:  '',
      amountmonth3:  '',
    },
    validationSchema: validationSchema,
    onSubmit: (values) => {
      navigate('/main', { state: values });
    },
  });

  return (
    <div className="form-page">
      <h2>Enter Forms Details</h2>
    <form onSubmit={formik.handleSubmit} className='form-container'>

    <div className='input-main1'>
      <div className='b1-input'>
      <label htmlFor="Name">Full Name :</label>
      <input  name="Name"  type="text"  onChange={formik.handleChange}  value={formik.values.Name} className={formik.errors.Name && formik.touched.Name ? 'input-error' : ''} onBlur={formik.handleBlur}/><br />
      {formik.errors.Name && formik.touched.Name && <span className="error-message">{formik.errors.Name}</span>}<br />
      <label htmlFor="Address">Address :</label>
      <input 
        name="Address" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.Address}
        className={formik.errors.Address && formik.touched.Address ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.Address && formik.touched.Address && <span className="error-message">{formik.errors.Address}</span>}
      <br />
      <label htmlFor="mobile">Mobile Number :</label><br />
      <input 
        name="mobile" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.mobile}
        className={formik.errors.mobile && formik.touched.mobile ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.mobile && formik.touched.mobile && <span className="error-message">{formik.errors.mobile}</span>}
      <br />
      <label htmlFor="city">City :</label><br />
      <input 
        name="city" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.city}
        className={formik.errors.city && formik.touched.city ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.city && formik.touched.city && <span className="error-message">{formik.errors.city}</span>}
      <br />
      <label htmlFor="district">District :</label><br />
      <input 
        name="district" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.district}
        className={formik.errors.district && formik.touched.district ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.district && formik.touched.district && <span className="error-message">{formik.errors.district}</span>}
      <br />
      <label htmlFor="census">Census Code :</label><br />
      <input 
        name="census" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.census}
        className={formik.errors.census && formik.touched.census ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.census && formik.touched.census && <span className="error-message">{formik.errors.census}</span>}
      <br />
      <label htmlFor="feeder">Feeder Code :</label><br />
      <input 
        name="feeder" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.feeder}
        className={formik.errors.feeder && formik.touched.feeder ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.feeder && formik.touched.feeder && <span className="error-message">{formik.errors.feeder}</span>}
      <br />
      <label htmlFor="subdivision">Subdivision Name :</label><br />
      <input 
        name="subdivision" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.subdivision}
        className={formik.errors.subdivision && formik.touched.subdivision ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.subdivision && formik.touched.subdivision && <span className="error-message">{formik.errors.subdivision}</span>}
      <br />
      <label htmlFor="routecode">Route Code :</label><br />
      <input 
        name="routecode" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.routecode}
        className={formik.errors.routecode && formik.touched.routecode ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.routecode && formik.touched.routecode && <span className="error-message">{formik.errors.routecode}</span>}
      <br />
      <label htmlFor="consumerno">Consumer No :</label><br />
      <input 
        name="consumerno" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.consumerno}
        className={formik.errors.consumerno && formik.touched.consumerno ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.consumerno && formik.touched.consumerno && <span className="error-message">{formik.errors.consumerno}</span>}
      <br />
      <label htmlFor="meterno">Meter No :</label><br />
      <input 
        name="meterno" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.meterno}
        className={formik.errors.meterno && formik.touched.meterno ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.meterno && formik.touched.meterno && <span className="error-message">{formik.errors.meterno}</span>}
      <br />
    </div>

    <div className='b2-input'>

      <label htmlFor="billmonth">Bill Month :</label><br />
      <input 
        name="billmonth" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.billmonth} 
        placeholder='e.g: Oct , 2025'
        className={formik.errors.billmonth && formik.touched.billmonth ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.billmonth && formik.touched.billmonth && <span className="error-message">{formik.errors.billmonth}</span>}
      <br />

      <label htmlFor="billdate">Bill Date :</label><br />
      <input 
        className={`init ${formik.errors.billdate && formik.touched.billdate ? 'input-error' : ''}`}
        name="billdate" 
        type="date" 
        onChange={formik.handleChange} 
        value={formik.values.billdate}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.billdate && formik.touched.billdate && <span className="error-message">{formik.errors.billdate}</span>}
      <br />

      <label htmlFor="duedate">Due Date :</label><br />
      <input 
        className={`init ${formik.errors.duedate && formik.touched.duedate ? 'input-error' : ''}`}
        name="duedate" 
        type="date" 
        onChange={formik.handleChange} 
        value={formik.values.duedate}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.duedate && formik.touched.duedate && <span className="error-message">{formik.errors.duedate}</span>}
      <br />

      <label htmlFor="fromdate">From Date :</label><br />
      <input 
        className={`init ${formik.errors.fromdate && formik.touched.fromdate ? 'input-error' : ''}`}
        name="fromdate" 
        type="date" 
        onChange={formik.handleChange} 
        value={formik.values.fromdate}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.fromdate && formik.touched.fromdate && <span className="error-message">{formik.errors.fromdate}</span>}
      <br />
      <label htmlFor="todate">To Date :</label><br />
      <input 
        className={`init ${formik.errors.todate && formik.touched.todate ? 'input-error' : ''}`}
        name="todate" 
        type="date" 
        onChange={formik.handleChange} 
        value={formik.values.todate}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.todate && formik.touched.todate && <span className="error-message">{formik.errors.todate}</span>}
      <br />
      <label htmlFor="maxdemand">Max Demand :</label><br />
      <input 
        name="maxdemand" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.maxdemand}
        className={formik.errors.maxdemand && formik.touched.maxdemand ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.maxdemand && formik.touched.maxdemand && <span className="error-message">{formik.errors.maxdemand}</span>}
      <br />
      <label htmlFor="feedercode">Feeder Code :</label><br />
      <input 
        name="feedercode" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.feedercode}
        className={formik.errors.feedercode && formik.touched.feedercode ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.feedercode && formik.touched.feedercode && <span className="error-message">{formik.errors.feedercode}</span>}
      <br />
      <label htmlFor="meterrentcode">Meter Rent Code :</label><br />
      <input 
        name="meterrentcode" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.meterrentcode}
        className={formik.errors.meterrentcode && formik.touched.meterrentcode ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.meterrentcode && formik.touched.meterrentcode && <span className="error-message">{formik.errors.meterrentcode}</span>}
      <br />

      <label htmlFor="unitcr">Unit (current reading):</label><br />
      <input 
        name="unitcr" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.unitcr}
        className={formik.errors.unitcr && formik.touched.unitcr ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.unitcr && formik.touched.unitcr && <span className="error-message">{formik.errors.unitcr}</span>}
      <br />
      <label htmlFor="unitpr">Unit (past reading):</label><br />
      <input 
        name="unitpr" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.unitpr}
        className={formik.errors.unitpr && formik.touched.unitpr ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.unitpr && formik.touched.unitpr && <span className="error-message">{formik.errors.unitpr}</span>}
      <br />
      <label htmlFor="unitc">Unit (consumption):</label><br />
      <input 
        name="unitc" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.unitc}
        className={formik.errors.unitc && formik.touched.unitc ? 'input-error' : ''}
        onBlur={formik.handleBlur}
